    x1r = _mm256_load_pd(&in_re[8 * K + k]);
    x1i = _mm256_load_pd(&in_im[8 * K + k]);
    x2r = _mm256_load_pd(&in_re[16 * K + k]);
    x2i = _mm256_load_pd(&in_im[16 * K + k]);
    x3r = _mm256_load_pd(&in_re[24 * K + k]);
    x3i = _mm256_load_pd(&in_im[24 * K + k]);
