    x1r = _mm256_load_pd(&in_re[10 * K + k]);
    x1i = _mm256_load_pd(&in_im[10 * K + k]);
    x2r = _mm256_load_pd(&in_re[18 * K + k]);
    x2i = _mm256_load_pd(&in_im[18 * K + k]);
    x3r = _mm256_load_pd(&in_re[26 * K + k]);
    x3i = _mm256_load_pd(&in_im[26 * K + k]);
